page_group = [None] * 264  
def create_page_group(pagenum):
    page_group = [None] * 45          # 保持原有的索引结构
    for i in range(35, 37):           # 处理 i = 31, 32
        # 为当前 i 创建一个列表，长度 = 分段数量
        page_group[i] = [None] * (len(pagenum[i]) - 1)
        for j in range(len(pagenum[i]) - 1):
            start = pagenum[i][j]
            end = pagenum[i][j + 1]
            if start == end - 1:      # 连续的情况，只包含一个数
                page_group[i][j] = [start]
            else:                     # 不连续，填充整个区间
                page_group[i][j] = list(range(start, end))
    return page_group
def search_page_group(i):
    page_group = [None] * (len(pagenum[i]) - 1)
    for j in range(len(pagenum[i]) - 1):
        start = pagenum[i][j]
        end = pagenum[i][j + 1]
        if start == end - 1:      # 连续的情况，只包含一个数
            page_group[j] = [start]
        else:                     # 不连续，填充整个区间
            page_group[j] = list(range(start, end))
    return page_group
