# 在模块加载时自动构建，供全局 O(1) 查询


with open("MEWmap.json", 'r', encoding='utf-8') as f:
    _raw_map = json.load(f)

# 把字符串键转回 int，恢复原始结构
_page_group_map: dict[int, dict[int, list]] = {
    int(vol): {int(pg): grp for pg, grp in pages.items()}
    for vol, pages in _raw_map.items()
}


def get_page_group(volume: int, page: int) -> Optional[list]:
    """O(1) 查询"""
    try:
        return _page_group_map[volume].get(page)
    except (KeyError, TypeError):
        return None
def main():
    i=22
    html_content=""

    while i<=22:
        index_content=""
        vol_dir=out_dir/f"{i}"
        vol_dir.mkdir(exist_ok=True,parents=True)
        #page_group[i] = [None] * (len(pagenum[i]) - 1)
        for j in range(len(pagenum[i])-1):
            start = pagenum[i][j]
            end = pagenum[i][j + 1]
            #if start == end - 1:      # 连续的情况，只包含一个数
